/// Validation Op Fixture Generator
///
/// This test generates known-good byte fixtures for validation Ops,
/// and also tests deserializing JavaScript-generated bytes.
///
/// Run with: cargo test --test validation_op_fixtures -- --nocapture
use base64::{engine::general_purpose::STANDARD, Engine};
use holo_hash::{ActionHash, AgentPubKey, AnyLinkableHash, EntryHash};
use holochain_serialized_bytes::prelude::*;
use holochain_zome_types::prelude::*;

// Same deterministic values as the TypeScript fixture tests
fn make_hash32(seed: u8) -> [u8; 32] {
    [seed; 32]
}

fn make_agent_pubkey(seed: u8) -> AgentPubKey {
    AgentPubKey::from_raw_32(make_hash32(seed).to_vec())
}

fn make_action_hash(seed: u8) -> ActionHash {
    ActionHash::from_raw_32(make_hash32(seed).to_vec())
}

fn make_entry_hash(seed: u8) -> EntryHash {
    EntryHash::from_raw_32(make_hash32(seed).to_vec())
}

fn make_signature() -> Signature {
    Signature(vec![0xbb; 64].try_into().unwrap())
}

fn fixed_timestamp() -> Timestamp {
    // 2024-01-01 00:00:00 UTC in microseconds
    Timestamp(1704067200000000)
}

fn make_create_action() -> Action {
    Action::Create(Create {
        author: make_agent_pubkey(0x11),
        timestamp: fixed_timestamp(),
        action_seq: 5,
        prev_action: make_action_hash(0x22),
        entry_type: EntryType::App(AppEntryDef {
            entry_index: 0.into(),
            zome_index: 0.into(),
            visibility: EntryVisibility::Public,
        }),
        entry_hash: make_entry_hash(0x33),
        weight: EntryRateWeight::default(),
    })
}

fn make_create_link_action() -> Action {
    Action::CreateLink(CreateLink {
        author: make_agent_pubkey(0x11),
        timestamp: fixed_timestamp(),
        action_seq: 8,
        prev_action: make_action_hash(0x22),
        base_address: AnyLinkableHash::from(make_entry_hash(0x33)),
        target_address: AnyLinkableHash::from(make_entry_hash(0x44)),
        zome_index: 0.into(),
        link_type: 0.into(),
        tag: LinkTag::new(vec![0x01, 0x02, 0x03]),
        weight: RateWeight::default(),
    })
}

fn make_signed_action_hashed(action: Action) -> SignedActionHashed {
    SignedActionHashed::with_presigned(
        ActionHashed::with_pre_hashed(action, make_action_hash(0xaa)),
        make_signature(),
    )
}

fn make_entry() -> Entry {
    Entry::App(AppEntryBytes(SerializedBytes::from(UnsafeBytes::from(
        vec![1u8, 2, 3, 4, 5],
    ))))
}

#[test]
fn generate_store_record_op_fixture() {
    let action = make_create_action();
    let signed = make_signed_action_hashed(action);
    let record = Record::new(signed, Some(make_entry()));

    let op = Op::StoreRecord(StoreRecord { record });

    // Serialize using holochain_serialized_bytes (rmp-serde with struct_map)
    let inner_bytes = holochain_serialized_bytes::encode(&op).unwrap();
    println!("StoreRecord Op inner bytes ({} bytes):", inner_bytes.len());
    println!("  base64: {}", STANDARD.encode(&inner_bytes));
    println!(
        "  first 80 hex: {}",
        inner_bytes
            .iter()
            .take(80)
            .map(|b| format!("{b:02x}"))
            .collect::<String>()
    );

    // Also show ExternIO wrapping (what actually goes to WASM memory)
    let extern_io = ExternIO::encode(&op).unwrap();
    let extern_io_bytes = holochain_serialized_bytes::encode(&extern_io).unwrap();
    println!("\nExternIO-wrapped ({} bytes):", extern_io_bytes.len());
    println!("  base64: {}", STANDARD.encode(&extern_io_bytes));
    println!(
        "  first 20 hex: {}",
        extern_io_bytes
            .iter()
            .take(20)
            .map(|b| format!("{b:02x}"))
            .collect::<String>()
    );

    // Verify round-trip
    let decoded: Op = holochain_serialized_bytes::decode(&inner_bytes).unwrap();
    println!("\nRound-trip: OK");
    match &decoded {
        Op::StoreRecord(sr) => {
            let action = sr.record.action();
            println!("  Action type: {:?}", action.action_type());
        }
        _ => panic!("Wrong Op variant"),
    }
}

