#[test]
fn deserialize_js_store_record_create() {
    // JS-encoded StoreRecord (Create) Op bytes from TypeScript
    let js_b64 = "";

    let js_bytes = STANDARD.decode(js_b64).unwrap();
    println!("JS StoreRecord (Create) bytes: {} bytes", js_bytes.len());

    let result: Result<Op, _> = holochain_serialized_bytes::decode(&js_bytes);
    match result {
        Ok(op) => {
            println!("SUCCESS: JS bytes deserialized to Op");
            match &op {
                Op::StoreRecord(sr) => {
                    let action = sr.record.action();
                    println!("  Action type: {:?}", action.action_type());
                    if let Action::Create(c) = action {
                        println!("  Author: {:?}", c.author);
                        println!("  Entry type: {:?}", c.entry_type);
                        println!("  Weight: {:?}", c.weight);
                    }
                }
                _ => println!("  Wrong variant: expected StoreRecord"),
            }
        }
        Err(e) => {
            println!("FAILED: {e}");
            // Show first 40 bytes as hex for debugging
            let hex: String = js_bytes
                .iter()
                .take(40)
                .map(|b| format!("{b:02x}"))
                .collect();
            println!("  First 40 bytes: {hex}");
        }
    }
}

